import { Component, OnInit } from "@angular/core";
import { ECollectService } from "src/app/core/services/e-collect.service";
import { ECollectSettings } from "src/app/views/Models/References/ECollectData";

@Component({
  selector: "app-e-collect-management",
  templateUrl: "./e-collect-management.page.html",
  styleUrls: ["./e-collect-management.page.scss"],
})
export class ECollectManagementPage implements OnInit {
  ecollectRefs: ECollectSettings[];
  originalECollectRefs: ECollectSettings[];

  constructor(private ecollectService: ECollectService) {}

  async ngOnInit() {
    await this.fetchECollectRefs();
  }

  async fetchECollectRefs() {
    this.ecollectRefs = (
      await this.ecollectService.getECollectRefsWithSettings()
    ).map((x) => {
      return {
        ...x,
        active_rec: x.active_rec == 1 ? true : false,
        auto_post: x.auto_post == 1 ? true : false,
      };
    });
    this.originalECollectRefs = JSON.parse(JSON.stringify(this.ecollectRefs));
  }

  reset() {
    this.ecollectRefs = this.originalECollectRefs;
  }

  async save() {
    this.ecollectService
      .updateECollectRefs(
        this.ecollectRefs.map((x) => {
          return {
            ...x,
            active_rec: x.active_rec ? 1 : 0,
            auto_post: x.auto_post ? 1 : 0,
          };
        })
      )
      .then(async () => {
        await this.fetchECollectRefs();
      });
  }
}
