import { Injectable } from "@angular/core";
import { EnvService } from "./env.service";
import { HttpClient } from "@angular/common/http";
import {
  EbcBank,
  EbcBankBranch,
  EbcEligibleLoan,
  EbcPendingTransaction,
  EbcUndisbursedTransaction,
} from "src/app/views/Models/E-Disb/EgyptianBanksCompany";
import { ECollectSettings } from "src/app/views/Models/References/ECollectData";

@Injectable({
  providedIn: "root",
})
export class ECollectService {
  constructor(private env: EnvService, private http: HttpClient) {}

  public async getECollectRefsWithSettings(): Promise<ECollectSettings[]> {
    return await this.http
      .get<ECollectSettings[]>(
        `${this.env.API_URL}api/Settings/GetECollectRefsWithSettings`
      )
      .toPromise();
  }

  public async updateECollectRefs(
    ecollectSettings: ECollectSettings[]
  ): Promise<boolean> {
    return await this.http
      .post<boolean>(
        `${this.env.API_URL}api/Settings/UpdateECollectRefsSettings`,
        ecollectSettings
      )
      .toPromise();
  }
}
